SELECT t.id AS id, s.code AS siteCode, s.name AS siteName, t.ranking_type AS rankingType, t.category AS category, t.trigger_type AS triggerType, t.status AS status, t.progress AS progress, t.fetched_count AS fetchedCount, t.error_message AS errorMessage, t.created_by AS createdBy, t.created_at AS createdAt, t.started_at AS startedAt, t.finished_at AS finishedAt, CASE WHEN t.finished_at IS NOT NULL AND t.started_at IS NOT NULL THEN TIMESTAMPDIFF(MICROSECOND, t.started_at, t.finished_at) DIV 1000 ELSE NULL END AS durationMs FROM crawl_task t JOIN site s ON t.site_id = s.id
t.status = #{status} AND s.code = #{siteCode} AND t.trigger_type = #{triggerType} AND t.created_at >= #{startTime} AND t.created_at <= #{endTime}
ORDER BY t.created_at DESC LIMIT #{offset}, #{size}

SELECT COUNT(*)
FROM crawl_task t
JOIN site s ON t.site_id = s.id

    t.status = #{status}
    AND s.code = #{siteCode}
    AND t.trigger_type = #{triggerType}
    AND t.created_at >= #{startTime}
    AND t.created_at <= #{endTime}
